+    std.debug.print("                    PyAOT (Zig)    Rust rustbpe    Speedup\n", .{});
+    std.debug.print("-" ** 60 ++ "\n", .{});
+    const estimate_1m = @divFloor(encode_per_iter_us * 1_000_000, @as(u128, test_text.len));
+    std.debug.print("Encoding (1M chars) {:>8}μs        {:>8}μs       {d:.2}x\n", .{
